module RefModule(
	input wire clk,
	input wire reset,
	input wire signal,
	output reg edge_detected
);reg signal_d;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
		if (reset) begin
			signal_d <= 1'b0;
			edge_detected <= 1'b0;
		end else begin
			edge_detected <= signal & ~signal_d;
			signal_d <= signal;
		end
	end
endmodule
